export declare const TYPE_DEFINITIONS = "\n## Type Definitions\n\n> **front_id** (on Student, StudentEvent, Team): user-facing numeric ID shown on badges / scorecards / rosters. When the user says \"team 31\" or \"student 142\" they mean front_id. Always report back to the user using front_id + name, never internal IDs.\n\ninterface Event {\n  event_id: number;\n  event_name: string;\n  event_date: string;           // YYYY-MM-DD\n  host_id: number;\n  ticket_price_cents: number;\n  max_team_size: number;\n  published: boolean;\n  reg_frozen: boolean;\n  email: string | null;\n  logo: string | null;\n  summary: string | null;\n  waivers: any | null;\n  payment_provider_event_internal_id: string | null;\n  host?: Host;\n}\n\ninterface Host {\n  host_id: number;\n  host_name: string;\n  email: string | null;\n  logo: string | null;\n  styles: any | null;\n}\n\ninterface Student {\n  student_id: string;\n  first_name: string | null;\n  last_name: string | null;\n  email: string;\n  grade: number | null;\n}\n\ninterface StudentEvent {\n  student_event_id: number;\n  student_id: string;\n  event_id: number;\n  team_id: number | null;\n  org_id: number | null;\n  front_id: number | null;     // \u2B50 user-facing ID \u2014 always use this when reporting\n  waiver: string | null;\n  created_at: string;\n  person?: Student;              // joined from students table\n  team?: Team;\n  org_event?: OrgEvent;\n}\n\ninterface Team {\n  team_id: number;\n  team_name: string | null;\n  event_id: number;\n  org_id: number | null;\n  join_code: string | null;\n  front_id: number | null;     // \u2B50 user-facing ID \u2014 always use this when reporting\n  invites: string[] | null;\n  members?: StudentEvent[];      // populated by SDK\n}\n\ninterface Org {\n  org_id: number;\n  name: string;\n  address: string | null;\n  address_latitude: number | null;\n  address_longitude: number | null;\n}\n\ninterface OrgEvent {\n  org_event_id: number;\n  org_id: number;\n  event_id: number;\n  join_code: string | null;\n  invites: string[] | null;\n  org?: Org;\n  event?: Event;\n}\n\ninterface Coach {\n  coach_id: string;\n  first_name: string | null;\n  last_name: string | null;\n  email: string;\n}\n\ninterface OrgCoach {\n  org_id: number;\n  coach_id: string;\n  person?: Coach;\n}\n\ninterface TicketOrder {\n  id: number;\n  event_id: number;\n  student_id: string | null;\n  org_id: number | null;\n  quantity: number;\n  order_id: string | null;\n  ticket_service: \"stripe\" | \"eventbrite\" | \"admin\" | \"humanitix\";\n  created_at: string;\n  refund_requests?: RefundRequest[];\n}\n\ninterface RefundRequest {\n  id: number;\n  ticket_id: number;\n  quantity: number;\n  refund_status: \"PENDING\" | \"APPROVED\" | \"DENIED\";\n  request_reason: string | null;\n  response_reason: string | null;\n  created_at: string;\n}\n\ninterface Test {\n  test_id: number;\n  test_name: string;\n  event_id: number;\n  is_team: boolean;\n  visible: boolean;\n  test_mode: \"Standard\" | \"Puzzle\" | \"Guts\" | \"Meltdown\";\n  start_time: string | null;\n  end_time: string | null;\n  length: number | null;\n  division: string | null;\n}\n\ninterface TestTaker {\n  test_taker_id: number;\n  test_id: number;\n  student_id: string | null;\n  team_id: number | null;\n  score: number | null;\n  start_time: string | null;\n  end_time: string | null;\n  front_id?: number | null;      // enriched for individual tests\n}\n\ninterface GradedTestAnswer {\n  test_answer_id: number | null;\n  test_id: number | null;\n  test_taker_id: number | null;\n  test_problem_id: number | null;\n  test_problem_number: number | null;\n  test_problem_page: number | null;\n  test_name: string | null;\n  answer_latex: string | null;    // the student's submitted answer\n  score: number | null;\n  points: number | null;          // max points for the problem\n  correct: boolean | null;\n  last_edited_time: string | null; // ISO timestamp of the last edit to this answer\n}\n\ninterface TestProblem {\n  test_problem_id: number;\n  test_id: number;\n  problem_id: number;\n  problem_number: number;\n  points: number | null;\n  page_number: number | null;\n}\n\ninterface CustomField {\n  custom_field_id: number;\n  key: string;\n  label: string;\n  custom_field_type: \"text\" | \"number\" | \"date\" | \"paragraph\" | \"email\" | \"phone\" | \"multiple_choice\" | \"checkboxes\" | \"dropdown\";\n  custom_field_table: \"students\" | \"teams\" | \"orgs\";\n  choices: string[] | null;\n  required: boolean;\n  hidden: boolean;\n}\n";
